# --- MODULE 13 : Les instructions SIMD ---
exercises.extend([
    {"id": "ex-mod13-1", "type": "quiz", "question": "Que signifie SIMD ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Single Instruction, Multiple Data."}, {"id": "b", "text": "System Internal Memory Device."}, {"id": "c", "text": "Simple Integer Math Divider."}], "correctId": "a", "explanation": "Une seule instruction assembleur exécute le même calcul sur plusieurs valeurs en même temps."}},
    {"id": "ex-mod13-2", "type": "quiz", "question": "Combien de bits fait un registre YMM (utilisé par AVX) ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "64 bits"}, {"id": "b", "text": "128 bits"}, {"id": "c", "text": "256 bits"}], "correctId": "c", "explanation": "Un registre YMM de 256 bits peut contenir 8 entiers de 32 bits, ou 8 floats."}},
    {"id": "ex-mod13-3", "type": "quiz", "question": "Quelle est la principale source de plantages (crash) lors de l'utilisation manuelle d'instructions SIMD (SSE/AVX) avec la mémoire ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "L'utilisation de nombres négatifs."}, {"id": "b", "text": "Une division par zéro."}, {"id": "c", "text": "Un mauvais alignement de la mémoire (ex: adresse non multiple de 16 ou 32 octets)."}], "correctId": "c", "explanation": "Les instructions comme 'movdqa' (Move Double Quadword Aligned) exigent un alignement strict, sinon c'est le crash garanti."}},
    {"id": "ex-mod13-4", "type": "fill-blank", "question": "Addition vectorielle (AVX)", "difficulty": "medium", "xpReward": 35, "data": {"codeTemplate": "; Additionner 8 floats simultanément\n; Le préfixe 'v' (VEX) permet une syntaxe non-destructrice à 3 opérandes\n__BLANK__ ymm0, ymm1, ymm2", "blanks": [{"id": "1", "answer": "vaddps", "hint": "Vector ADD Packed Single-precision."}], "explanation": "vaddps (AVX) additionne les éléments de ymm1 et ymm2 et met le résultat dans ymm0 sans écraser ymm1."}},
    {"id": "ex-mod13-5", "type": "quiz", "question": "Qu'est-ce que l'Auto-Vectorization ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Le fait que le CPU active AVX tout seul."}, {"id": "b", "text": "La capacité du compilateur (GCC, Clang) à analyser une boucle for classique et à la transformer automatiquement en instructions SIMD."}, {"id": "c", "text": "Un système de pilotage de voiture autonome."}], "correctId": "b", "explanation": "C'est l'optimisation (-O3) la plus redoutable. Le compilateur remplace votre boucle par une version 8 fois plus rapide."}},
    {"id": "ex-mod13-6", "type": "quiz", "question": "Quel est le risque de l'utilisation intensive des instructions AVX-512 (registres ZMM de 512 bits) ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "La baisse de la fréquence d'horloge du processeur (Downclocking) à cause de la surchauffe extrême."}, {"id": "b", "text": "La suppression de Windows."}, {"id": "c", "text": "Le blocage de la carte graphique."}], "correctId": "a", "explanation": "Historiquement (Intel Skylake), exécuter des instructions AVX-512 consommait tellement d'énergie que le CPU baissait sa fréquence pour tout le monde."}},
    {"id": "ex-mod13-7", "type": "drag-drop", "question": "La hiérarchie des registres vectoriels SIMD", "difficulty": "hard", "xpReward": 50, "data": {"items": [{"id": "1", "text": "MMX (64 bits, partage les registres x87) - Obsolète"}, {"id": "2", "text": "SSE (XMM0-XMM15, 128 bits)"}, {"id": "3", "text": "AVX / AVX2 (YMM0-YMM15, 256 bits)"}, {"id": "4", "text": "AVX-512 (ZMM0-ZMM31, 512 bits)"}], "correctOrder": ["1", "2", "3", "4"], "instruction": "Classez les technologies SIMD de la plus ancienne/petite à la plus récente/grande.", "explanation": "Notez que la partie basse d'un registre YMM EST le registre XMM correspondant, tout comme EAX est dans RAX."}},
    {"id": "ex-mod13-8", "type": "fill-blank", "question": "Splatting / Broadcast", "difficulty": "hard", "xpReward": 50, "data": {"codeTemplate": "; Copier un seul float présent en mémoire dans TOUTES les positions d'un registre YMM (8 floats identiques)\n__BLANK__ ymm0, [ma_constante_float]", "blanks": [{"id": "1", "answer": "vbroadcastss", "hint": "Vector Broadcast Single Scalar."}], "explanation": "C'est vital pour multiplier tout un tableau de vecteurs par une seule constante (ex: augmenter la luminosité de tous les pixels)."}},
    {"id": "ex-mod13-9", "type": "quiz", "question": "Qu'est-ce qu'une opération 'Packed' vs 'Scalar' en SIMD ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Packed agit sur TOUS les éléments du registre simultanément. Scalar n'agit QUE sur le premier élément (le plus bas) du registre."}, {"id": "b", "text": "Packed compresse les données. Scalar les décompresse."}, {"id": "c", "text": "Aucune différence."}], "correctId": "a", "explanation": "Exemple : `addps` (Packed Single) additionne 4 floats. `addss` (Scalar Single) additionne seulement le 1er float et laisse les autres intacts."}},
    {"id": "ex-mod13-10", "type": "code-correction", "question": "Alignement SSE strict", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "movups xmm0, [memoire_non_alignee]\nmovaps xmm1, [memoire_non_alignee]", "correctCode": "movups xmm0, [memoire_non_alignee]\nmovups xmm1, [memoire_non_alignee]", "hints": ["L'instruction 'aps' (Aligned Packed Single) crashera si la mémoire n'est pas alignée sur 16 octets."], "explanation": "Si vous n'êtes pas certain de l'alignement, utilisez toujours la version Unaligned (movups, vmovups). Avec AVX, la pénalité de performance de l'Unaligned est devenue quasi-nulle."}}
])

# --- MODULE 14 : Les Conventions d'Appel (ABI) ---
exercises.extend([
    {"id": "ex-mod14-1", "type": "quiz", "question": "Sous System V ABI (Linux x86-64), dans quel ordre sont passés les 6 premiers arguments entiers d'une fonction ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Sur la pile, de droite à gauche."}, {"id": "b", "text": "RDI, RSI, RDX, RCX, R8, R9"}, {"id": "c", "text": "RAX, RBX, RCX, RDX, RDI, RSI"}], "correctId": "b", "explanation": "Cette séquence est utilisée universellement sur Linux/macOS."}},
    {"id": "ex-mod14-2", "type": "quiz", "question": "Où passe-t-on le 7ème argument d'une fonction sous Linux x86-64 ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Dans R10."}, {"id": "b", "text": "Sur la pile (Stack), poussé avant l'appel."}, {"id": "c", "text": "On ne peut pas avoir 7 arguments."}], "correctId": "b", "explanation": "Une fois les registres épuisés, on utilise le mécanisme historique : la pile."}},
    {"id": "ex-mod14-3", "type": "quiz", "question": "Quelle est la particularité très stricte de l'ABI Windows x64 concernant le 'Shadow Space' ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "L'appelant (caller) DOIT allouer systématiquement 32 octets sur la pile avant chaque 'call', même si la fonction n'a aucun argument."}, {"id": "b", "text": "Les ombres ne sont pas gérées par le CPU."}, {"id": "c", "text": "L'appelé (callee) doit vider le cache."}], "correctId": "a", "explanation": "Ces 32 octets servent de zone de sauvegarde (Home Space) pour que la fonction appelée puisse y déverser RCX/RDX/R8/R9 si elle a besoin de les utiliser."}},
    {"id": "ex-mod14-4", "type": "fill-blank", "question": "Registres Volatils vs Non-Volatils", "difficulty": "medium", "xpReward": 35, "data": {"codeTemplate": "; La fonction appelée DOIT restaurer certains registres (Non-Volatils) avant de revenir.\n; Exemple type sur Linux :\npush __BLANK__\n; ... utilisation ...\npop __BLANK__\nret", "blanks": [{"id": "1", "answer": "rbx", "hint": "Registre Base."}, {"id": "2", "answer": "rbx", "hint": "Restauration."}], "explanation": "RBX, RBP, R12-R15 sont Callee-Saved (non-volatils). RDI, RSI, RAX, RCX sont Caller-Saved (volatils)."}},
    {"id": "ex-mod14-5", "type": "quiz", "question": "Comment retourne-t-on un gros objet C++ (ex: un struct de 128 octets) qui ne rentre pas dans RAX ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "L'appelant alloue l'espace mémoire pour l'objet et passe un pointeur 'caché' (souvent dans RDI) à l'appelé pour qu'il le remplisse (Return Value Optimization)."}, {"id": "b", "text": "On le retourne via la carte graphique."}, {"id": "c", "text": "On utilise R8, R9, R10 et R11 simultanément."}], "correctId": "a", "explanation": "L'objet n'est techniquement jamais 'retourné', il est construit 'sur place' directement dans la Frame de l'appelant."}},
    {"id": "ex-mod14-6", "type": "quiz", "question": "Pourquoi la convention d'appel 'fastcall' a-t-elle été inventée à l'époque du 32-bits (x86) ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Parce qu'à l'origine (cdecl), TOUS les arguments passaient par la pile (très lent). Fastcall passait les 2 ou 3 premiers dans ECX/EDX."}, {"id": "b", "text": "Pour faire des sauts plus loin."}, {"id": "c", "text": "Pour exécuter le programme plus vite."}], "correctId": "a", "explanation": "Le passage par registre est immensément plus rapide que les push/pop sur la pile."}},
    {"id": "ex-mod14-7", "type": "drag-drop", "question": "Différence Linux vs Windows x64", "difficulty": "hard", "xpReward": 50, "data": {"items": [{"id": "1", "text": "Arguments Windows"}, {"id": "2", "text": "Arguments Linux"}, {"id": "3", "text": "Shadow Space Windows"}, {"id": "4", "text": "Red Zone Linux (128 octets sous RSP)"}], "correctOrder": ["1", "2", "3", "4"], "instruction": "Associez les concepts. Mettez d'abord Windows (Args: RCX, RDX, R8, R9), puis Linux (Args: RDI, RSI...), puis Shadow Space (32 octets obligatoires pour Win), puis Red Zone (Zone sûre de 128 bytes pour Linux).", "explanation": "La Red Zone Linux permet aux fonctions feuilles (leaf functions) d'utiliser la pile sans même bouger RSP !"}},
    {"id": "ex-mod14-8", "type": "fill-blank", "question": "Nettoyage de pile de l'Appelant", "difficulty": "hard", "xpReward": 50, "data": {"codeTemplate": "push rdx ; Arg 8\npush rcx ; Arg 7\ncall grosse_fonction\n; L'appelant doit restaurer la pile !\nadd rsp, __BLANK__", "blanks": [{"id": "1", "answer": "16", "hint": "2 push de 8 octets."}], "explanation": "Sous cdecl/SystemV, c'est celui qui appelle (Caller) qui a la responsabilité de retirer les arguments de la pile après le 'call'."}},
    {"id": "ex-mod14-9", "type": "quiz", "question": "Qu'est-ce que la 'Name Mangling' (Décoration de nom) en C++ ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Le compilateur modifie le nom d'une fonction (ex: void func(int) devient _Z4funci) pour encoder ses paramètres, permettant la surcharge (Overloading)."}, {"id": "b", "text": "L'ajout d'emojis dans les commentaires."}, {"id": "c", "text": "La suppression des variables."}], "correctId": "a", "explanation": "C'est pour cela qu'on utilise `extern \"C\"` : pour désactiver le Mangling et garder le nom pur afin d'être appelé depuis l'Assembleur ou le C."}},
    {"id": "ex-mod14-10", "type": "code-correction", "question": "Alignement de la pile à 16 octets", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "; On appelle printf sans aligner la pile\npush rax ; La pile est maintenant désalignée (terminant par 8)\nmov rdi, chaine\ncall printf", "correctCode": "sub rsp, 8 ; Aligner la pile sur 16 octets\npush rax ; 8 + 8 = 16\nmov rdi, chaine\ncall printf\nadd rsp, 16 ; Nettoyage", "hints": ["La pile DOIT être alignée sur 16 octets avant d'appeler une fonction C."], "explanation": "La glibc Linux utilise des instructions AVX qui crashent lamentablement (Segfault) si la pile n'est pas un multiple de 16 au moment du CALL."}}
])

